240вҶ’+#!/usr/bin/env node
241вҶ’+
242вҶ’+/**
243вҶ’+ * Deus CLI вҖ” run Deus from the command line.
244вҶ’+ *
245вҶ’+ * Smart default:
246вҶ’+ *   npx deus-machine        Desktop вҶ’ install/launch app. Server вҶ’ headless.
247вҶ’+ *
248вҶ’+ * Commands:
249вҶ’+ *   deus                    Auto-detect best mode
250вҶ’+ *   deus start              Start headless server (backend + agent-server)
251вҶ’+ *   deus install            Download and install the desktop app
252вҶ’+ *   deus pair               Generate a pairing code for remote access
253вҶ’+ *   deus login              Configure AI agent authentication
254вҶ’+ *   deus status             Show server info and connected devices
255вҶ’+ */
256вҶ’+
257вҶ’+import { parseArgs } from "node:util";
258вҶ’+import { start } from "./start.js";
259вҶ’+import { installDesktop, hasDisplay, findInstalledApp, launchDesktop } from "./desktop.js";
260вҶ’+import { pair } from "./pair.js";
261вҶ’+import { runAuthSetup } from "./login.js";
262вҶ’+import { showStatus } from "./status.js";
263вҶ’+import {
264вҶ’+  animatedBanner,
265вҶ’+  banner,
266вҶ’+  c,
267вҶ’+  sym,
268вҶ’+  blank,
269вҶ’+  info,
270вҶ’+  hint,
271вҶ’+  success,
272вҶ’+  error,
273вҶ’+  warn,
274вҶ’+  gradientText,
275вҶ’+} from "./ui.js";
276вҶ’+
277вҶ’+function printHelp(version: string) {
278вҶ’+  banner(version);
279вҶ’+  console.log(`  ${c.bold("Usage:")}   deus ${c.dim("[command] [options]")}`);
280вҶ’+  blank();
281вҶ’+
282вҶ’+  console.log(`  ${c.bold("Commands:")}`);
283вҶ’+  console.log(`    ${c.cyan("(none)")}        Auto-detect: launch desktop app or start server`);
284вҶ’+  console.log(`    ${c.cyan("start")}        Start headless server ${c.dim("(backend + agent-server)")}`);
285вҶ’+  console.log(`    ${c.cyan("install")}      Download and install the desktop app`);
286вҶ’+  console.log(`    ${c.cyan("pair")}         Generate a pairing code for remote access`);
287вҶ’+  console.log(`    ${c.cyan("login")}        Configure AI agent authentication`);
288вҶ’+  console.log(`    ${c.cyan("status")}       Show server info and connected devices`);
289вҶ’+  blank();
290вҶ’+
291вҶ’+  console.log(`  ${c.bold("Options")} ${c.dim("(start):")}`);
292вҶ’+  console.log(`    ${c.cyan("--data-dir")}   Directory for database and data files`);
293вҶ’+  blank();
294вҶ’+
295вҶ’+  console.log(`  ${c.bold("Options")} ${c.dim("(install):")}`);
296вҶ’+  console.log(`    ${c.cyan("--version")}    Install a specific version ${c.dim("(default: latest)")}`);
297вҶ’+  blank();
298вҶ’+
299вҶ’+  console.log(`  ${c.bold("Examples:")}`);
300вҶ’+  console.log(`    ${c.dim("$")} deus                    ${c.dim("# auto-detect mode")}`);
301вҶ’+  console.log(`    ${c.dim("$")} deus start               ${c.dim("# run headless server")}`);
302вҶ’+  console.log(`    ${c.dim("$")} deus install              ${c.dim("# install desktop app")}`);
303вҶ’+  console.log(`    ${c.dim("$")} deus pair                 ${c.dim("# generate pairing code")}`);
304вҶ’+  console.log(`    ${c.dim("$")} deus login                ${c.dim("# set up AI agent auth")}`);
305вҶ’+  console.log(`    ${c.dim("$")} deus status               ${c.dim("# show server info")}`);
306вҶ’+  blank();
307вҶ’+
308вҶ’+  console.log(`  ${c.bold("Quick start:")}`);
309вҶ’+  console.log(`    ${c.dim("$")} npx deus-machine          ${c.dim("# just works, no install needed")}`);
310вҶ’+  blank();
311вҶ’+}
312вҶ’+
313вҶ’+async function main() {
314вҶ’+  const args = process.argv.slice(2);
315вҶ’+  const command = args[0] && !args[0].startsWith("-") ? args[0] : null;
316вҶ’+  const commandArgs = command ? args.slice(1) : args;
317вҶ’+
318вҶ’+  // Load version once
319вҶ’+  const pkg = await import("../package.json", { with: { type: "json" } });
320вҶ’+  const version = pkg.default.version;
321вҶ’+
322вҶ’+  // Version (plain output, no banner)
323вҶ’+  if (args.includes("--version") || args.includes("-v")) {
324вҶ’+    console.log(version);
325вҶ’+    process.exit(0);
326вҶ’+  }
327вҶ’+
328вҶ’+  // Help
329вҶ’+  if (command === "help" || args.includes("--help") || args.includes("-h")) {
330вҶ’+    printHelp(version);
331вҶ’+    process.exit(0);
332вҶ’+  }
333вҶ’+
334вҶ’+  // Commands that don't need the full banner
335вҶ’+  const quickCommands = ["pair", "status", "login"];
336вҶ’+  if (!command || !quickCommands.includes(command)) {
337вҶ’+    await animatedBanner(version);
338вҶ’+  }
339вҶ’+
340вҶ’+  // Resolve command
341вҶ’+  const resolvedCommand = command ?? autoDetect();
342вҶ’+
343вҶ’+  switch (resolvedCommand) {
344вҶ’+    // в”Җв”Җ Start headless server в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
345вҶ’+    case "start":
346вҶ’+    case "serve": { // backward compat
347вҶ’+      const { values } = parseArgs({
348вҶ’+        args: commandArgs,
349вҶ’+        options: {
350вҶ’+          "data-dir": { type: "string" },
351вҶ’+        },
352вҶ’+        strict: false,
353вҶ’+      });
354вҶ’+
355вҶ’+      await start({
356вҶ’+        dataDir: values["data-dir"] as string | undefined,
357вҶ’+      });
358вҶ’+      break;
359вҶ’+    }
360вҶ’+
361вҶ’+    // в”Җв”Җ Install desktop app в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
362вҶ’+    case "install":
363вҶ’+    case "desktop": { // backward compat
364вҶ’+      // Check if already installed вҖ” just launch
365вҶ’+      const installedPath = findInstalledApp();
366вҶ’+      if (installedPath) {
367вҶ’+        success(`Deus is installed at ${c.dim(installedPath)}`);
368вҶ’+        blank();
369вҶ’+        launchDesktop(installedPath);
370вҶ’+        success("Launching Deus...");
371вҶ’+        blank();
372вҶ’+        return;
373вҶ’+      }
374вҶ’+
375вҶ’+      const { values } = parseArgs({
376вҶ’+        args: commandArgs,
377вҶ’+        options: {
378вҶ’+          version: { type: "string", default: "latest" },
379вҶ’+        },
380вҶ’+        strict: false,
381вҶ’+      });
382вҶ’+
383вҶ’+      await installDesktop({ version: values.version as string });
384вҶ’+      break;
385вҶ’+    }
386вҶ’+
387вҶ’+    // в”Җв”Җ Generate pairing code в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
388вҶ’+    case "pair": {
389вҶ’+      await pair();
390вҶ’+      break;
391вҶ’+    }
392вҶ’+
393вҶ’+    // в”Җв”Җ Auth setup в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
394вҶ’+    case "login": {
395вҶ’+      blank();
396вҶ’+      await runAuthSetup({ force: true });
397вҶ’+      blank();
398вҶ’+      break;
399вҶ’+    }
400вҶ’+
401вҶ’+    // в”Җв”Җ Server status в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
402вҶ’+    case "status": {
403вҶ’+      await showStatus();
404вҶ’+      break;
405вҶ’+    }
406вҶ’+
407вҶ’+    default:
408вҶ’+      error(`Unknown command: ${c.bold(resolvedCommand)}`);
409вҶ’+      blank();
410вҶ’+      hint(`Run ${c.cyan("deus --help")} to see available commands.`);
411вҶ’+      blank();
412вҶ’+      process.exit(1);
413вҶ’+  }
414вҶ’+}
415вҶ’+
416вҶ’+/**
417вҶ’+ * Auto-detect the best mode based on environment.
418вҶ’+ *
419вҶ’+ * Desktop machine with app installed вҶ’ launch the desktop app
420вҶ’+ * Desktop machine without app вҶ’ install the desktop app
421вҶ’+ * Server/SSH/Docker вҶ’ start headless server
422вҶ’+ */
423вҶ’+function autoDetect(): "start" | "install" {
424вҶ’+  if (!hasDisplay()) {
425вҶ’+    info("No display detected " + c.dim("вҖ” starting in server mode"));
426вҶ’+    blank();
427вҶ’+    return "start";
428вҶ’+  }
429вҶ’+
430вҶ’+  // Desktop machine вҖ” desktop app is the primary experience
431вҶ’+  const installedPath = findInstalledApp();
432вҶ’+  if (installedPath) {
433вҶ’+    return "install"; // will detect installed and launch
434вҶ’+  }
435вҶ’+
436вҶ’+  info("Desktop environment detected " + c.dim("вҖ” installing Deus app"));
437вҶ’+  blank();
438вҶ’+  return "install";
439вҶ’+}
440вҶ’+
441вҶ’+main().catch((err) => {
442вҶ’+  blank();
443вҶ’+  error(`${err.message || err}`);
444вҶ’+  blank();
445вҶ’+  process.exit(1);
446вҶ’+});
