453вҶ’+/**
454вҶ’+ * CLI configuration persistence.
455вҶ’+ *
456вҶ’+ * Stores CLI-specific state at ~/.config/deus/config.json (XDG-compliant).
457вҶ’+ * Separate from the backend's preferences.json вҖ” this tracks onboarding
458вҶ’+ * completion, auth method choice, and server runtime info.
459вҶ’+ */
460вҶ’+
461вҶ’+import { readFileSync, writeFileSync, existsSync, unlinkSync, renameSync, mkdirSync } from "node:fs";
462вҶ’+import { join } from "node:path";
463вҶ’+import { homedir, platform } from "node:os";
464вҶ’+import { randomBytes } from "node:crypto";
465вҶ’+
466вҶ’+// в”Җв”Җ Config Types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
467вҶ’+
468вҶ’+export interface DeusConfig {
469вҶ’+  onboarding_completed: boolean;
470вҶ’+  auth_method: "claude_cli" | "api_key" | "env" | "skipped" | null;
471вҶ’+  anthropic_api_key?: string;
472вҶ’+  relay_enabled: boolean;
473вҶ’+  installed_at?: string;
474вҶ’+}
475вҶ’+
476вҶ’+export interface ServerInfo {
477вҶ’+  pid: number;
478вҶ’+  backendPort: number;
479вҶ’+  agentServerUrl: string;
480вҶ’+  startedAt: string;
481вҶ’+}
482вҶ’+
483вҶ’+const DEFAULT_CONFIG: DeusConfig = {
484вҶ’+  onboarding_completed: false,
485вҶ’+  auth_method: null,
486вҶ’+  relay_enabled: true,
487вҶ’+};
488вҶ’+
489вҶ’+// в”Җв”Җ Paths в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
490вҶ’+
491вҶ’+export function getConfigDir(): string {
492вҶ’+  const os = platform();
493вҶ’+  if (os === "darwin") {
494вҶ’+    return join(homedir(), ".config", "deus");
495вҶ’+  }
496вҶ’+  if (os === "win32") {
497вҶ’+    return join(process.env.APPDATA || join(homedir(), "AppData", "Roaming"), "deus");
498вҶ’+  }
499вҶ’+  // Linux / other вҖ” XDG
500вҶ’+  return join(process.env.XDG_CONFIG_HOME || join(homedir(), ".config"), "deus");

