678вҶ’+export async function installDesktop(options: DesktopOptions): Promise<void> {
679вҶ’+  const { version } = options;
680вҶ’+  const os = platform();
681вҶ’+  const cpuArch = arch();
682вҶ’+
683вҶ’+  // Determine which asset to download
684вҶ’+  const assetPattern = getAssetPattern(os, cpuArch);
685вҶ’+  if (!assetPattern) {
686вҶ’+    error(`Unsupported platform: ${os} ${cpuArch}`);
687вҶ’+    blank();
688вҶ’+    hint("Supported: macOS (arm64/x64), Windows (x64), Linux (x64)");
689вҶ’+    hint(`Or run ${c.cyan("deus start")} to run as a headless server.`);
690вҶ’+    blank();
691вҶ’+    process.exit(1);
692вҶ’+  }
693вҶ’+
694вҶ’+  kv("Platform", `${os} ${cpuArch}`, 10);
695вҶ’+  kv("Package", c.dim(assetPattern.description), 10);
696вҶ’+  blank();
697вҶ’+
698вҶ’+  // Fetch release info
699вҶ’+  const s1 = createSpinner("Fetching latest release...");
700вҶ’+  const release = await fetchRelease(version);
701вҶ’+
702вҶ’+  if (!release) {
703вҶ’+    s1.fail("Could not find a release on GitHub");
704вҶ’+    blank();
705вҶ’+    hint(`Repo: ${c.dim(GITHUB_REPO)}`);
706вҶ’+    hint("Make sure the repository has published releases.");
707вҶ’+    hint(`Or run ${c.cyan("deus start")} to run as a headless server.`);
708вҶ’+    blank();
709вҶ’+    process.exit(1);
710вҶ’+  }
711вҶ’+
712вҶ’+  s1.succeed(`Found release ${c.cyan(release.tag_name)}`);
713вҶ’+
714вҶ’+  // Find matching asset
715вҶ’+  const asset = release.assets.find((a) => assetPattern.matcher(a.name));
716вҶ’+  if (!asset) {
717вҶ’+    error(`No matching installer for ${os} ${cpuArch}`);
718вҶ’+    blank();
719вҶ’+    hint("Available downloads:");
720вҶ’+    for (const a of release.assets) {
721вҶ’+      hint(`  ${a.name}`);
722вҶ’+    }
723вҶ’+    blank();
724вҶ’+    process.exit(1);
725вҶ’+  }
726вҶ’+
727вҶ’+  // Download
728вҶ’+  const downloadDir = join(tmpdir(), "deus-installer");
729вҶ’+  mkdirSync(downloadDir, { recursive: true });
730вҶ’+  const downloadPath = join(downloadDir, asset.name);
731вҶ’+
732вҶ’+  await downloadFile(asset.browser_download_url, downloadPath);
733вҶ’+
734вҶ’+  // Install
735вҶ’+  const s3 = createSpinner("Installing...");
736вҶ’+  const installed = await installForPlatform(os, downloadPath, s3);
737вҶ’+
738вҶ’+  // Cleanup temp file
739вҶ’+  try {
740вҶ’+    unlinkSync(downloadPath);
741вҶ’+  } catch {}
742вҶ’+
743вҶ’+  if (installed) {
744вҶ’+    blank();
745вҶ’+    success("Deus is ready!");
746вҶ’+    blank();
747вҶ’+  }
748вҶ’+}
