750вҶ’+function getAssetPattern(
751вҶ’+  os: string,
752вҶ’+  cpuArch: string
753вҶ’+): { matcher: (name: string) => boolean; description: string } | null {
754вҶ’+  switch (os) {
755вҶ’+    case "darwin": {
756вҶ’+      const archSuffix = cpuArch === "arm64" ? "arm64" : "x64";
757вҶ’+      return {
758вҶ’+        matcher: (name) => name.endsWith(".dmg") && name.includes(archSuffix),
759вҶ’+        description: `macOS DMG (${archSuffix})`,
760вҶ’+      };
761вҶ’+    }
762вҶ’+    case "win32":
763вҶ’+      return {
764вҶ’+        matcher: (name) => name.endsWith(".exe") && !name.includes("blockmap"),
765вҶ’+        description: "Windows installer (exe)",
766вҶ’+      };
767вҶ’+    case "linux":
768вҶ’+      return {
769вҶ’+        matcher: (name) => name.endsWith(".AppImage"),
770вҶ’+        description: "Linux AppImage",
771вҶ’+      };
772вҶ’+    default:
773вҶ’+      return null;
774вҶ’+  }
775вҶ’+}
776вҶ’+
777вҶ’+async function fetchRelease(version: string): Promise<GithubRelease | null> {
778вҶ’+  const endpoint =
779вҶ’+    version === "latest"
780вҶ’+      ? `https://api.github.com/repos/${GITHUB_REPO}/releases/latest`
781вҶ’+      : `https://api.github.com/repos/${GITHUB_REPO}/releases/tags/${version}`;
782вҶ’+
783вҶ’+  return new Promise((resolve) => {
784вҶ’+    get(
785вҶ’+      endpoint,
786вҶ’+      { headers: { "User-Agent": "deus-cli", Accept: "application/vnd.github.v3+json" } },
787вҶ’+      (res) => {
788вҶ’+        if (res.statusCode === 302 || res.statusCode === 301) {
789вҶ’+          const loc = res.headers.location;
790вҶ’+          if (loc) {
791вҶ’+            get(loc, { headers: { "User-Agent": "deus-cli" } }, (r) => {
792вҶ’+              collectBody(r).then((b) => {
793вҶ’+                try { resolve(JSON.parse(b)); } catch { resolve(null); }
794вҶ’+              });
795вҶ’+            }).on("error", () => resolve(null));
796вҶ’+            return;
797вҶ’+          }
798вҶ’+        }
799вҶ’+        if (res.statusCode !== 200) { resolve(null); return; }
800вҶ’+        collectBody(res).then((b) => {
801вҶ’+          try { resolve(JSON.parse(b)); } catch { resolve(null); }
802вҶ’+        });
803вҶ’+      }
804вҶ’+    ).on("error", () => resolve(null));
805вҶ’+  });
806вҶ’+}
807вҶ’+
808вҶ’+function collectBody(res: IncomingMessage): Promise<string> {
809вҶ’+  return new Promise((resolve) => {
810вҶ’+    let body = "";
811вҶ’+    res.on("data", (chunk: Buffer) => (body += chunk.toString()));
812вҶ’+    res.on("end", () => resolve(body));
813вҶ’+    res.on("error", () => resolve(""));
814вҶ’+  });
815вҶ’+}
816вҶ’+
817вҶ’+async function downloadFile(url: string, dest: string): Promise<void> {
818вҶ’+  return new Promise((resolve, reject) => {
819вҶ’+    const download = (downloadUrl: string) => {
820вҶ’+      get(downloadUrl, { headers: { "User-Agent": "deus-cli" } }, (res) => {
821вҶ’+        if (res.statusCode === 302 || res.statusCode === 301) {
822вҶ’+          const loc = res.headers.location;
823вҶ’+          if (loc) { download(loc); return; }
824вҶ’+        }
825вҶ’+
826вҶ’+        if (res.statusCode !== 200) {
827вҶ’+          reject(new Error(`Download failed with status ${res.statusCode}`));
828вҶ’+          return;
829вҶ’+        }
830вҶ’+
831вҶ’+        const totalSize = parseInt(res.headers["content-length"] || "0", 10);
832вҶ’+        let downloaded = 0;
833вҶ’+
834вҶ’+        const file = createWriteStream(dest);
835вҶ’+        res.on("data", (chunk: Buffer) => {
836вҶ’+          downloaded += chunk.length;
837вҶ’+          if (totalSize > 0) {
838вҶ’+            progressBar(downloaded, totalSize, formatBytes(downloaded) + " / " + formatBytes(totalSize));
839вҶ’+          }
840вҶ’+        });
841вҶ’+        res.pipe(file);
842вҶ’+        file.on("finish", () => {
843вҶ’+          file.close();
844вҶ’+          progressBarDone(`Downloaded ${c.dim(formatBytes(totalSize))}`);
845вҶ’+          resolve();
846вҶ’+        });
847вҶ’+        file.on("error", reject);
848вҶ’+      }).on("error", reject);
849вҶ’+    };
850вҶ’+
851вҶ’+    download(url);
852вҶ’+  });
853вҶ’+}
854вҶ’+
855вҶ’+function formatBytes(bytes: number): string {
856вҶ’+  if (bytes < 1024) return `${bytes} B`;
857вҶ’+  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
858вҶ’+  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
859вҶ’+}
860вҶ’+
861вҶ’+async function installForPlatform(
862вҶ’+  os: string,
863вҶ’+  filePath: string,
864вҶ’+  s: ReturnType<typeof createSpinner>
865вҶ’+): Promise<boolean> {
866вҶ’+  switch (os) {
867вҶ’+    case "darwin": {
868вҶ’+      try {
869вҶ’+        const mountOutput = execSync(`hdiutil attach "${filePath}" -nobrowse`, {
870вҶ’+          encoding: "utf-8",
871вҶ’+        });
872вҶ’+
873вҶ’+        const mountPoint = mountOutput
874вҶ’+          .split("\n")
875вҶ’+          .filter((line) => line.includes("/Volumes/"))
876вҶ’+          .map((line) => line.trim().split("\t").pop()?.trim())
877вҶ’+          .find(Boolean);
878вҶ’+
879вҶ’+        if (!mountPoint) {
880вҶ’+          s.fail("Could not mount disk image");
881вҶ’+          return false;
882вҶ’+        }
883вҶ’+
884вҶ’+        const appName = "Deus.app";
885вҶ’+        const appPath = `${mountPoint}/${appName}`;
886вҶ’+        const destPath = `/Applications/${appName}`;
887вҶ’+
888вҶ’+        if (existsSync(appPath)) {
889вҶ’+          execSync(`cp -R "${appPath}" "${destPath}"`, { stdio: "pipe" });
890вҶ’+          s.succeed(`Installed to ${c.dim("/Applications/Deus.app")}`);
891вҶ’+
892вҶ’+          launchDesktop(destPath);
893вҶ’+        } else {
894вҶ’+          s.warn("DMG mounted вҖ” drag Deus to Applications to finish");
895вҶ’+        }
896вҶ’+
897вҶ’+        execSync(`hdiutil detach "${mountPoint}" -quiet`, { stdio: "pipe" });
898вҶ’+        return true;
899вҶ’+      } catch {
900вҶ’+        s.fail("Auto-install failed вҖ” opening DMG manually");
901вҶ’+        execSync(`open "${filePath}"`);
902вҶ’+        return false;
903вҶ’+      }
904вҶ’+    }
905вҶ’+
906вҶ’+    case "win32": {
907вҶ’+      s.succeed("Launching installer...");
908вҶ’+      spawn(filePath, [], { detached: true, stdio: "ignore" }).unref();
909вҶ’+      hint("Follow the on-screen instructions to complete installation.");
910вҶ’+      return true;
911вҶ’+    }
912вҶ’+
913вҶ’+    case "linux": {
914вҶ’+      execSync(`chmod +x "${filePath}"`);
915вҶ’+      const installDir = join(homedir(), ".local", "bin");
916вҶ’+      mkdirSync(installDir, { recursive: true });
917вҶ’+      const destPath = join(installDir, "Deus.AppImage");
918вҶ’+      execSync(`cp "${filePath}" "${destPath}"`);
919вҶ’+      s.succeed(`Installed to ${c.dim(destPath)}`);
920вҶ’+
921вҶ’+      launchDesktop(destPath);
922вҶ’+      return true;
923вҶ’+    }
924вҶ’+
925вҶ’+    default:
926вҶ’+      s.fail("Unsupported platform");
927вҶ’+      return false;
928вҶ’+  }
929вҶ’+}
