1586вҶ’+/**
1587вҶ’+ * Interactive terminal prompt primitives.
1588вҶ’+ *
1589вҶ’+ * Zero dependencies вҖ” uses raw ANSI escape codes and process.stdin in raw mode.
1590вҶ’+ * Provides select (arrow keys), text input (with masking), and confirm prompts.
1591вҶ’+ */
1592вҶ’+
1593вҶ’+import { c, sym } from "./ui.js";
1594вҶ’+
1595вҶ’+const ESC = "\x1b[";
1596вҶ’+
1597вҶ’+// в”Җв”Җ Select в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
1598вҶ’+
1599вҶ’+export interface SelectOption<T> {
1600вҶ’+  label: string;
1601вҶ’+  value: T;
1602вҶ’+  hint?: string;
1603вҶ’+}
1604вҶ’+
1605вҶ’+/**
1606вҶ’+ * Arrow-key single-select from a list of options.
1607вҶ’+ * Returns the selected value.
1608вҶ’+ */
1609вҶ’+export async function select<T>(opts: {
1610вҶ’+  message: string;
1611вҶ’+  options: SelectOption<T>[];
1612вҶ’+}): Promise<T> {
1613вҶ’+  const { message, options } = opts;
1614вҶ’+  const stdin = process.stdin;
1615вҶ’+  const stream = process.stderr;
1616вҶ’+
1617вҶ’+  let selected = 0;
1618вҶ’+
1619вҶ’+  // Print message
1620вҶ’+  stream.write(`  ${message}\n`);
1621вҶ’+
1622вҶ’+  function render() {
1623вҶ’+    // Move cursor up to overwrite options
1624вҶ’+    if (selected >= 0) {
1625вҶ’+      stream.write(`${ESC}${options.length}A`);
1626вҶ’+    }
1627вҶ’+
1628вҶ’+    for (let i = 0; i < options.length; i++) {
1629вҶ’+      const opt = options[i];
1630вҶ’+      const isActive = i === selected;
1631вҶ’+      const pointer = isActive ? c.cyan(sym.pointer) : " ";
1632вҶ’+      const label = isActive ? c.cyan(opt.label) : c.dim(opt.label);
1633вҶ’+      const hintText = opt.hint ? (isActive ? `  ${c.dim(opt.hint)}` : `  ${c.dim(opt.hint)}`) : "";
1634вҶ’+      stream.write(`${ESC}2K  ${pointer} ${label}${hintText}\n`);
1635вҶ’+    }
1636вҶ’+  }
1637вҶ’+
1638вҶ’+  // Initial render
1639вҶ’+  for (let i = 0; i < options.length; i++) stream.write("\n");
1640вҶ’+  render();
1641вҶ’+
1642вҶ’+  return new Promise<T>((resolve) => {
1643вҶ’+    const wasRaw = stdin.isRaw;
1644вҶ’+    stdin.setRawMode(true);
1645вҶ’+    stdin.resume();
1646вҶ’+
1647вҶ’+    function cleanup() {
1648вҶ’+      stdin.setRawMode(wasRaw ?? false);
1649вҶ’+      stdin.pause();
1650вҶ’+      stdin.removeListener("data", onData);
1651вҶ’+    }
1652вҶ’+
1653вҶ’+    function onData(buf: Buffer) {
1654вҶ’+      const key = buf.toString();
1655вҶ’+
1656вҶ’+      // Ctrl+C
1657вҶ’+      if (key === "\x03") {
1658вҶ’+        cleanup();
1659вҶ’+        stream.write("\n");
1660вҶ’+        process.exit(130);
1661вҶ’+      }
1662вҶ’+
1663вҶ’+      // Arrow up
1664вҶ’+      if (key === "\x1b[A" || key === "k") {
1665вҶ’+        selected = (selected - 1 + options.length) % options.length;
1666вҶ’+        render();
1667вҶ’+        return;
1668вҶ’+      }
1669вҶ’+
1670вҶ’+      // Arrow down
1671вҶ’+      if (key === "\x1b[B" || key === "j") {
1672вҶ’+        selected = (selected + 1) % options.length;
1673вҶ’+        render();
1674вҶ’+        return;
1675вҶ’+      }
1676вҶ’+
1677вҶ’+      // Enter
1678вҶ’+      if (key === "\r" || key === "\n") {
1679вҶ’+        cleanup();
1680вҶ’+        // Clear options and show selected
1681вҶ’+        stream.write(`${ESC}${options.length}A`);
1682вҶ’+        for (let i = 0; i < options.length; i++) {
1683вҶ’+          stream.write(`${ESC}2K\n`);
1684вҶ’+        }
1685вҶ’+        stream.write(`${ESC}${options.length}A`);
1686вҶ’+        stream.write(`${ESC}2K  ${c.green(sym.tick)} ${options[selected].label}\n`);
1687вҶ’+        resolve(options[selected].value);
