1849вҶ’+/**
1850вҶ’+ * Minimal QR code generator for terminal display.
1851вҶ’+ *
1852вҶ’+ * Zero dependencies. Supports byte mode, Error Correction Level L,
1853вҶ’+ * versions 1-5. Uses Unicode half-block characters for compact rendering.
1854вҶ’+ *
1855вҶ’+ * Based on the QR code specification (ISO/IEC 18004).
1856вҶ’+ */
1857вҶ’+
1858вҶ’+// в”Җв”Җ GF(256) Arithmetic в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
1859вҶ’+
1860вҶ’+// QR codes use GF(256) with primitive polynomial x^8 + x^4 + x^3 + x^2 + 1 (0x11d)
1861вҶ’+const EXP = new Uint8Array(256);
1862вҶ’+const LOG = new Uint8Array(256);
1863вҶ’+
1864вҶ’+(() => {
1865вҶ’+  let x = 1;
1866вҶ’+  for (let i = 0; i < 255; i++) {
1867вҶ’+    EXP[i] = x;
1868вҶ’+    LOG[x] = i;
1869вҶ’+    x = (x << 1) ^ (x & 0x80 ? 0x11d : 0);
1870вҶ’+  }
1871вҶ’+  EXP[255] = EXP[0];
1872вҶ’+})();
1873вҶ’+
1874вҶ’+function gfMul(a: number, b: number): number {
1875вҶ’+  if (a === 0 || b === 0) return 0;
1876вҶ’+  return EXP[(LOG[a] + LOG[b]) % 255];
1877вҶ’+}
1878вҶ’+
1879вҶ’+// в”Җв”Җ Reed-Solomon в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
1880вҶ’+
1881вҶ’+function rsGeneratorPoly(n: number): Uint8Array {
1882вҶ’+  let g = new Uint8Array([1]);
1883вҶ’+  for (let i = 0; i < n; i++) {
1884вҶ’+    const next = new Uint8Array(g.length + 1);
1885вҶ’+    for (let j = 0; j < g.length; j++) {
1886вҶ’+      next[j] ^= g[j];
1887вҶ’+      next[j + 1] ^= gfMul(g[j], EXP[i]);
1888вҶ’+    }
1889вҶ’+    g = next;
1890вҶ’+  }
1891вҶ’+  return g;
1892вҶ’+}
1893вҶ’+
1894вҶ’+function rsEncode(data: Uint8Array, ecCount: number): Uint8Array {
1895вҶ’+  const gen = rsGeneratorPoly(ecCount);
1896вҶ’+  const result = new Uint8Array(data.length + ecCount);
1897вҶ’+  result.set(data);
1898вҶ’+
1899вҶ’+  for (let i = 0; i < data.length; i++) {
1900вҶ’+    const coef = result[i];
1901вҶ’+    if (coef !== 0) {
1902вҶ’+      for (let j = 0; j < gen.length; j++) {
1903вҶ’+        result[i + j] ^= gfMul(gen[j], coef);
1904вҶ’+      }
1905вҶ’+    }
1906вҶ’+  }
1907вҶ’+
1908вҶ’+  return result.slice(data.length);
1909вҶ’+}
1910вҶ’+
1911вҶ’+// в”Җв”Җ Version Info в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
1912вҶ’+
1913вҶ’+// [total codewords, ec codewords per block, num blocks] for Level L
1914вҶ’+const VERSION_INFO: [number, number, number][] = [
1915вҶ’+  [0, 0, 0],       // v0 placeholder
1916вҶ’+  [26, 7, 1],      // v1: 26 total, 7 EC, 1 block вҶ’ 19 data
1917вҶ’+  [44, 10, 1],     // v2: 44 total, 10 EC вҶ’ 34 data
1918вҶ’+  [70, 15, 1],     // v3: 70 total, 15 EC вҶ’ 55 data
1919вҶ’+  [100, 20, 1],    // v4: 100 total, 20 EC вҶ’ 80 data
1920вҶ’+  [134, 26, 1],    // v5: 134 total, 26 EC вҶ’ 108 data
1921вҶ’+];
1922вҶ’+
1923вҶ’+// Alignment pattern positions by version (v2+)
1924вҶ’+const ALIGNMENT_POS: number[][] = [
1925вҶ’+  [],          // v0
1926вҶ’+  [],          // v1
1927вҶ’+  [6, 18],     // v2
1928вҶ’+  [6, 22],     // v3
1929вҶ’+  [6, 26],     // v4
1930вҶ’+  [6, 30],     // v5
1931вҶ’+];
1932вҶ’+
1933вҶ’+function getVersion(dataLen: number): number {
1934вҶ’+  for (let v = 1; v <= 5; v++) {
1935вҶ’+    const [total, ec] = VERSION_INFO[v];
1936вҶ’+    const dataCapacity = total - ec;
1937вҶ’+    // Byte mode overhead: 4 bits mode + 8/16 bits length + data + 4 bits terminator
1938вҶ’+    const overhead = v <= 9 ? 2 : 3; // mode + length indicator bytes (approx)
1939вҶ’+    if (dataLen + overhead <= dataCapacity) return v;
1940вҶ’+  }
1941вҶ’+  throw new Error("Data too long for QR version 1-5");
1942вҶ’+}
1943вҶ’+
1944вҶ’+// в”Җв”Җ Data Encoding в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
1945вҶ’+
1946вҶ’+function encodeData(data: string, version: number): Uint8Array {
1947вҶ’+  const [totalCW, ecCW] = VERSION_INFO[version];
1948вҶ’+  const dataCW = totalCW - ecCW;
1949вҶ’+  const buf = new Uint8Array(dataCW);
1950вҶ’+
1951вҶ’+  // Bit writer
1952вҶ’+  let bitPos = 0;
1953вҶ’+  function writeBits(val: number, count: number) {
1954вҶ’+    for (let i = count - 1; i >= 0; i--) {
1955вҶ’+      if (val & (1 << i)) {
1956вҶ’+        buf[bitPos >> 3] |= 0x80 >> (bitPos & 7);
1957вҶ’+      }
1958вҶ’+      bitPos++;
1959вҶ’+    }
1960вҶ’+  }
1961вҶ’+
1962вҶ’+  // Mode indicator: byte mode = 0100
1963вҶ’+  writeBits(0b0100, 4);
1964вҶ’+
1965вҶ’+  // Character count: 8 bits for v1-9
1966вҶ’+  writeBits(data.length, 8);
1967вҶ’+
1968вҶ’+  // Data bytes
1969вҶ’+  for (let i = 0; i < data.length; i++) {
1970вҶ’+    writeBits(data.charCodeAt(i) & 0xff, 8);
1971вҶ’+  }
1972вҶ’+
1973вҶ’+  // Terminator
1974вҶ’+  writeBits(0, Math.min(4, dataCW * 8 - bitPos));
1975вҶ’+
1976вҶ’+  // Pad to byte boundary
1977вҶ’+  bitPos = Math.ceil(bitPos / 8) * 8;
1978вҶ’+
1979вҶ’+  // Pad codewords (0xEC, 0x11 alternating)
1980вҶ’+  let padByte = 0;
1981вҶ’+  const padPatterns = [0xec, 0x11];
1982вҶ’+  while (bitPos < dataCW * 8) {
1983вҶ’+    writeBits(padPatterns[padByte % 2], 8);
1984вҶ’+    padByte++;
1985вҶ’+  }
1986вҶ’+
1987вҶ’+  return buf;
1988вҶ’+}
