+/**
+ * Interactive terminal prompt primitives.
+ *
+ * Zero dependencies вҖ” uses raw ANSI escape codes and process.stdin in raw mode.
+ * Provides select (arrow keys), text input (with masking), and confirm prompts.
+ */
+
+import { c, sym } from "./ui.js";
+
+const ESC = "\x1b[";
+
+// в”Җв”Җ Select в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
+
+export interface SelectOption<T> {
+  label: string;
+  value: T;
+  hint?: string;
+}
+
+/**
+ * Arrow-key single-select from a list of options.
+ * Returns the selected value.
+ */
+export async function select<T>(opts: {
+  message: string;
+  options: SelectOption<T>[];
+}): Promise<T> {
+  const { message, options } = opts;
+  const stdin = process.stdin;
+  const stream = process.stderr;
+
+  let selected = 0;
+
+  // Print message
