+      stdin.removeListener("data", onData);
+    }
+
+    function onData(buf: Buffer) {
+      const key = buf.toString().toLowerCase();
+
+      // Ctrl+C
+      if (key === "\x03") {
+        cleanup();
+        stream.write("\n");
+        process.exit(130);
+      }
+
+      if (key === "y") {
