2117вҶ’+function scoreMask(matrix: number[][], size: number): number {
2118вҶ’+  let score = 0;
2119вҶ’+
2120вҶ’+  // Penalty 1: adjacent same-color modules in rows/cols
2121вҶ’+  for (let r = 0; r < size; r++) {
2122вҶ’+    let count = 1;
2123вҶ’+    for (let c = 1; c < size; c++) {
2124вҶ’+      if (matrix[r][c] === matrix[r][c - 1]) {
2125вҶ’+        count++;
2126вҶ’+        if (count === 5) score += 3;
2127вҶ’+        else if (count > 5) score += 1;
2128вҶ’+      } else {
2129вҶ’+        count = 1;
2130вҶ’+      }
2131вҶ’+    }
2132вҶ’+  }
2133вҶ’+  for (let c = 0; c < size; c++) {
2134вҶ’+    let count = 1;
2135вҶ’+    for (let r = 1; r < size; r++) {
2136вҶ’+      if (matrix[r][c] === matrix[r - 1][c]) {
2137вҶ’+        count++;
2138вҶ’+        if (count === 5) score += 3;
2139вҶ’+        else if (count > 5) score += 1;
2140вҶ’+      } else {
2141вҶ’+        count = 1;
2142вҶ’+      }
2143вҶ’+    }
2144вҶ’+  }
2145вҶ’+
2146вҶ’+  // Penalty 3: finder-like patterns
2147вҶ’+  for (let r = 0; r < size; r++) {
