2164вҶ’+// Pre-computed format info strings for Level L (EC=01), masks 0-7
2165вҶ’+// Format: EC level (2 bits) + mask (3 bits) + BCH error correction (10 bits)
2166вҶ’+const FORMAT_STRINGS: number[] = [
2167вҶ’+  0x77c4, 0x72f3, 0x7daa, 0x789d, 0x662f, 0x6318, 0x6c41, 0x6976,
2168вҶ’+];
