2170вҶ’+function placeFormatInfo(matrix: number[][], size: number, maskIdx: number) {
2171вҶ’+  const bits = FORMAT_STRINGS[maskIdx];
2172вҶ’+
2173вҶ’+  // Bits 0-7 along left column (bottom to top at col 8)
2174вҶ’+  // Bits 8-14 along top row (left to right at row 8)
2175вҶ’+  const positions1: [number, number][] = [
2176вҶ’+    [8, 0], [8, 1], [8, 2], [8, 3], [8, 4], [8, 5],
2177вҶ’+    [8, 7], [8, 8], [7, 8],
2178вҶ’+    [5, 8], [4, 8], [3, 8], [2, 8], [1, 8], [0, 8],
2179вҶ’+  ];
2180вҶ’+  const positions2: [number, number][] = [
2181вҶ’+    [size - 1, 8], [size - 2, 8], [size - 3, 8], [size - 4, 8],
2182вҶ’+    [size - 5, 8], [size - 6, 8], [size - 7, 8],
2183вҶ’+    [8, size - 8], [8, size - 7], [8, size - 6], [8, size - 5],
2184вҶ’+    [8, size - 4], [8, size - 3], [8, size - 2], [8, size - 1],
2185вҶ’+  ];
2186вҶ’+
2187вҶ’+  for (let i = 0; i < 15; i++) {
2188вҶ’+    const bit = (bits >> i) & 1;
2189вҶ’+    const [r1, c1] = positions1[i];
2190вҶ’+    matrix[r1][c1] = bit;
2191вҶ’+    const [r2, c2] = positions2[i];
2192вҶ’+    matrix[r2][c2] = bit;
2193вҶ’+  }
