2198вҶ’+/**
2199вҶ’+ * Generate QR code as array of terminal-ready strings.
2200вҶ’+ * Uses Unicode half-block characters: two QR rows per terminal line.
2201вҶ’+ */
2202вҶ’+export function generateQR(data: string): string[] {
2203вҶ’+  const version = getVersion(data.length);
2204вҶ’+  const [totalCW, ecCW] = VERSION_INFO[version];
2205вҶ’+  const size = 17 + version * 4;
2206вҶ’+
2207вҶ’+  // Encode data
2208вҶ’+  const dataCodewords = encodeData(data, version);
2209вҶ’+  const ecCodewords = rsEncode(dataCodewords, ecCW);
2210вҶ’+
2211вҶ’+  // Interleave data + EC into bit stream
2212вҶ’+  const allCodewords = new Uint8Array(totalCW);
2213вҶ’+  allCodewords.set(dataCodewords);
2214вҶ’+  allCodewords.set(ecCodewords, dataCodewords.length);
2215вҶ’+
2216вҶ’+  const dataBits: number[] = [];
2217вҶ’+  for (const byte of allCodewords) {
2218вҶ’+    for (let bit = 7; bit >= 0; bit--) {
2219вҶ’+      dataBits.push((byte >> bit) & 1);
2220вҶ’+    }
2221вҶ’+  }
2222вҶ’+
2223вҶ’+  // Build matrix
2224вҶ’+  const { matrix } = createMatrix(version);
2225вҶ’+
2226вҶ’+  // Add fixed patterns
2227вҶ’+  addFinderPattern(matrix, 0, 0);
2228вҶ’+  addFinderPattern(matrix, 0, size - 7);
2229вҶ’+  addFinderPattern(matrix, size - 7, 0);
2230вҶ’+  addTimingPatterns(matrix, size);
2231вҶ’+
2232вҶ’+  // Alignment patterns (v2+)
2233вҶ’+  const alignPos = ALIGNMENT_POS[version];
2234вҶ’+  if (alignPos.length > 0) {
2235вҶ’+    for (const r of alignPos) {
2236вҶ’+      for (const c of alignPos) {
2237вҶ’+        // Skip if overlaps with finder
2238вҶ’+        if (r <= 8 && c <= 8) continue;
2239вҶ’+        if (r <= 8 && c >= size - 8) continue;
2240вҶ’+        if (r >= size - 8 && c <= 8) continue;
2241вҶ’+        addAlignmentPattern(matrix, r, c);
2242вҶ’+      }
2243вҶ’+    }
2244вҶ’+  }
2245вҶ’+
2246вҶ’+  // Reserve format area
2247вҶ’+  reserveFormatArea(matrix, size);
2248вҶ’+
2249вҶ’+  // Track which cells are reserved (non-data)
2250вҶ’+  const reserved: boolean[][] = matrix.map((r) => r.map((v) => v !== -1));
2251вҶ’+
2252вҶ’+  // Place data
2253вҶ’+  placeData(matrix, size, dataBits);
2254вҶ’+
2255вҶ’+  // Try all masks, pick best
2256вҶ’+  let bestMask = 0;
2257вҶ’+  let bestScore = Infinity;
2258вҶ’+
2259вҶ’+  for (let m = 0; m < 8; m++) {
2260вҶ’+    const masked = applyMask(matrix, reserved, size, m);
2261вҶ’+    placeFormatInfo(masked, size, m);
2262вҶ’+    const score = scoreMask(masked, size);
2263вҶ’+    if (score < bestScore) {
2264вҶ’+      bestScore = score;
2265вҶ’+      bestMask = m;
2266вҶ’+    }
2267вҶ’+  }
2268вҶ’+
2269вҶ’+  // Apply best mask
2270вҶ’+  const final = applyMask(matrix, reserved, size, bestMask);
2271вҶ’+  placeFormatInfo(final, size, bestMask);
2272вҶ’+
2273вҶ’+  // Render with quiet zone (1 module border)
2274вҶ’+  const qSize = size + 2;
2275вҶ’+  const lines: string[] = [];
2276вҶ’+
2277вҶ’+  // Use half-block rendering: two QR rows per terminal line
2278вҶ’+  // в–Ҳ = both black, в–Җ = top black / bottom white, в–„ = top white / bottom black, ' ' = both white
2279вҶ’+  // QR convention: dark module = 1, light = 0
2280вҶ’+  // Terminal: we render dark as block characters on default bg
2281вҶ’+
2282вҶ’+  for (let r = 0; r < qSize; r += 2) {
2283вҶ’+    let line = "";
2284вҶ’+    for (let c = 0; c < qSize; c++) {
2285вҶ’+      const topR = r - 1;
2286вҶ’+      const botR = r;
2287вҶ’+      const col = c - 1;
2288вҶ’+
2289вҶ’+      const top = (topR >= 0 && topR < size && col >= 0 && col < size) ? final[topR][col] : 0;
2290вҶ’+      const bot = (botR >= 0 && botR < size && col >= 0 && col < size) ? final[botR][col] : 0;
2291вҶ’+
2292вҶ’+      if (top && bot) {
2293вҶ’+        line += "\u2588"; // в–Ҳ full block
2294вҶ’+      } else if (top && !bot) {
2295вҶ’+        line += "\u2580"; // в–Җ upper half
2296вҶ’+      } else if (!top && bot) {
2297вҶ’+        line += "\u2584"; // в–„ lower half
2298вҶ’+      } else {
2299вҶ’+        line += " ";
2300вҶ’+      }
2301вҶ’+    }
2302вҶ’+    lines.push(line);
2303вҶ’+  }
2304вҶ’+
2305вҶ’+  return lines;
