3236вҶ’+/** Apply a gradient across a text string (from вҶ’ to RGB) */
3237вҶ’+export function gradientText(
3238вҶ’+  text: string,
3239вҶ’+  from: [number, number, number],
3240вҶ’+  to: [number, number, number]
3241вҶ’+): string {
3242вҶ’+  if (noColor) return text;
3243вҶ’+  let result = "";
3244вҶ’+  for (let i = 0; i < text.length; i++) {
3245вҶ’+    const t = text.length > 1 ? i / (text.length - 1) : 0;
3246вҶ’+    const r = Math.round(from[0] + (to[0] - from[0]) * t);
3247вҶ’+    const g = Math.round(from[1] + (to[1] - from[1]) * t);
3248вҶ’+    const b = Math.round(from[2] + (to[2] - from[2]) * t);
3249вҶ’+    result += rgb(r, g, b, text[i]);
3250вҶ’+  }
3251вҶ’+  return result;
