3270вҶ’+    dotCount++;
3271вҶ’+  }
3272вҶ’+
3273вҶ’+  const interval = setInterval(render, intervalMs);
3274вҶ’+  render();
3275вҶ’+
3276вҶ’+  return {
3277вҶ’+    stop() {
3278вҶ’+      if (stopped) return;
3279вҶ’+      stopped = true;
3280вҶ’+      clearInterval(interval);
3281вҶ’+      stream.write(`\r${ESC}2K`);
3282вҶ’+    },
3283вҶ’+  };
