 35вҶ’    external: [
 36вҶ’      // Native modules resolved at runtime
 37вҶ’      "better-sqlite3",
 38вҶ’      "node-pty",
 39вҶ’      "ws",
 40вҶ’    ],
 41вҶ’    packages: "external",
 42вҶ’    minify: false,
 43вҶ’    sourcemap: false,
 44вҶ’    logLevel: "info",
 45вҶ’  });
 46вҶ’
 47вҶ’  // Step 2: Create bin/ entry point
 48вҶ’  console.log("\n2. Creating bin/deus.js...");
 49вҶ’  mkdirSync(join(cliDir, "bin"), { recursive: true });
 50вҶ’  writeFileSync(join(cliDir, "bin/deus.js"), `#!/usr/bin/env node\nimport "../dist/cli.js";\n`, {
 51вҶ’    mode: 0o755,
 52вҶ’  });
 53вҶ’
 54вҶ’  // Step 3: Copy bundles for distribution
 55вҶ’  console.log("\n3. Copying bundles...");
 56вҶ’  const bundlesDir = join(cliDir, "bundles");
 57вҶ’  mkdirSync(bundlesDir, { recursive: true });
 58вҶ’
 59вҶ’  const copies: { src: string; dest: string; name: string; required: boolean }[] = [
 60вҶ’    {
 61вҶ’      src: join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs"),
 62вҶ’      dest: join(bundlesDir, "agent-server.bundled.cjs"),
 63вҶ’      name: "agent-server bundle",
 64вҶ’      required: true,
 65вҶ’    },
 66вҶ’    {
 67вҶ’      src: join(monorepoRoot, "apps/backend/dist/server.bundled.cjs"),
 68вҶ’      dest: join(bundlesDir, "server.bundled.cjs"),
 69вҶ’      name: "backend bundle",
 70вҶ’      required: true,
 71вҶ’    },
 72вҶ’  ];
 73вҶ’
 74вҶ’  let hasErrors = false;
 75вҶ’  for (const copy of copies) {
 76вҶ’    if (existsSync(copy.src)) {
 77вҶ’      cpSync(copy.src, copy.dest, { recursive: true });
 78вҶ’      console.log(`   вң“ ${copy.name}`);
 79вҶ’    } else if (copy.required) {
 80вҶ’      console.error(`   вң— ${copy.name} not found: ${copy.src}`);
 81вҶ’      hasErrors = true;
 82вҶ’    } else {
 83вҶ’      console.log(`   - ${copy.name} not found (optional, server will work without UI)`);
 84вҶ’    }
 85вҶ’  }
 86вҶ’
 87вҶ’  if (hasErrors) {
 88вҶ’    console.error("\nMissing required bundles. Run these first:");
 89вҶ’    console.error("  bun run build:agent-server");
 90вҶ’    console.error("  bun run build:backend");
 91вҶ’    // No web frontend needed вҖ” headless mode uses app.rundeus.com via relay
 92вҶ’    process.exit(1);
 93вҶ’  }
 94вҶ’
 95вҶ’  // Step 4: Generate a standalone package.json for the published CLI
 96вҶ’  console.log("\n4. Generating publish-ready package.json...");
 97вҶ’  const pkg = JSON.parse(readFileSync(join(cliDir, "package.json"), "utf-8"));
 98вҶ’  // Ensure we don't ship "private: true" or monorepo-specific fields
 99вҶ’  delete pkg.scripts;
100вҶ’  pkg.main = "dist/cli.js";
101вҶ’  pkg.type = "module";
102вҶ’  // Note: we don't overwrite вҖ” the original is fine for publishing
103вҶ’
104вҶ’  console.log("\nвң“ Build complete!");
105вҶ’  console.log(`  CLI: ${join(cliDir, "dist/cli.js")}`);
106вҶ’  console.log(`  Bin: ${join(cliDir, "bin/deus.js")}`);
107вҶ’  console.log(`  Bundles: ${bundlesDir}`);
108вҶ’  console.log("\nTo test locally:");
109вҶ’  console.log("  node apps/cli/bin/deus.js start");
110вҶ’  console.log("\nTo publish:");
111вҶ’  console.log("  cd apps/cli && npm publish");
112вҶ’}
113вҶ’
114вҶ’main().catch((err) => {
115вҶ’  console.error("Build failed:", err);
116вҶ’  process.exit(1);
117вҶ’});
