  1вҶ’/**
  2вҶ’ * Headless start mode вҖ” starts agent-server and backend.
  3вҶ’ *
  4вҶ’ * No web UI is served вҖ” remote users connect through app.rundeus.com via
  5вҶ’ * the cloud relay. This keeps the headless CLI minimal.
  6вҶ’ *
  7вҶ’ * Process orchestration:
  8вҶ’ * 1. Run onboarding (first run only вҖ” API key + remote access setup)
  9вҶ’ * 2. Start agent-server вҶ’ capture LISTEN_URL from stdout
 10вҶ’ * 3. Start backend with AGENT_SERVER_URL вҶ’ capture [BACKEND_PORT] from stdout
 11вҶ’ * 4. Show pairing code + QR for remote access
 12вҶ’ */
 13вҶ’
 14вҶ’import { spawn, execSync, type ChildProcess } from "node:child_process";
 15вҶ’import { existsSync } from "node:fs";
 16вҶ’import { join, resolve, dirname } from "node:path";
 17вҶ’import { fileURLToPath } from "node:url";
 18вҶ’import { platform, homedir } from "node:os";
 19вҶ’import { mkdirSync } from "node:fs";
 20вҶ’import {
 21вҶ’  spinner as createSpinner,
 22вҶ’  statusLine,
 23вҶ’  c,
 24вҶ’  sym,
 25вҶ’  box,
 26вҶ’  blank,
 27вҶ’  sleep,
 28вҶ’  success,
 29вҶ’  error,
 30вҶ’  warn,
 31вҶ’  hint,
 32вҶ’  kv,
 33вҶ’  gradientText,
 34вҶ’} from "./ui.js";
 35вҶ’import { loadConfig, hasCompletedOnboarding, writeServerInfo, clearServerInfo } from "./config.js";
 36вҶ’import { runOnboarding } from "./onboarding.js";
 37вҶ’import { showPairCode } from "./pair.js";
 38вҶ’import { formatUptime } from "./lib/format.js";
 39вҶ’
 40вҶ’const __filename = fileURLToPath(import.meta.url);
 41вҶ’const __dirname = dirname(__filename);
 42вҶ’
 43вҶ’export interface StartOptions {
 44вҶ’  dataDir?: string;
 45вҶ’}
 46вҶ’
 47вҶ’interface ProcessInfo {
 48вҶ’  process: ChildProcess;
 49вҶ’  name: string;
 50вҶ’}
 51вҶ’
 52вҶ’export async function start(options: StartOptions): Promise<void> {
 53вҶ’  const { dataDir } = options;
 54вҶ’
 55вҶ’  // в”Җв”Җ Onboarding (first run only) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
 56вҶ’  if (!hasCompletedOnboarding()) {
 57вҶ’    await runOnboarding();
 58вҶ’    blank();
 59вҶ’  }
 60вҶ’
 61вҶ’  const config = loadConfig();
 62вҶ’
 63вҶ’  // Resolve paths to bundles
 64вҶ’  const paths = resolveBundlePaths();
 65вҶ’  if (!paths) {
 66вҶ’    error("Could not find Deus bundles.");
 67вҶ’    blank();
 68вҶ’    hint(`Run ${c.cyan("bun run build:cli")} from the monorepo root first.`);
 69вҶ’    blank();
 70вҶ’    process.exit(1);
 71вҶ’  }
 72вҶ’
 73вҶ’  // Resolve Node binary
 74вҶ’  const nodeCmd = resolveNodeBinary();
 75вҶ’
 76вҶ’  // Resolve database
 77вҶ’  const dbPath = resolveDataDir(dataDir);
 78вҶ’  kv("Database", c.dim(dbPath));
 79вҶ’  blank();
 80вҶ’
 81вҶ’  // Track child processes for cleanup
 82вҶ’  const children: ProcessInfo[] = [];
 83вҶ’  let status: ReturnType<typeof statusLine> | null = null;
 84вҶ’
 85вҶ’  let shuttingDown = false;
 86вҶ’  let exitCode = 0;
 87вҶ’  function shutdown(code = 0) {
 88вҶ’    if (shuttingDown) return; // Prevent double-shutdown from rapid Ctrl+C
 89вҶ’    shuttingDown = true;
 90вҶ’    exitCode = code;
 91вҶ’
 92вҶ’    if (status) status.stop();
 93вҶ’    blank();
 94вҶ’
 95вҶ’    const msg = gradientText("Shutting down...", [167, 139, 250], [34, 211, 238]);
 96вҶ’    console.log(`  ${msg}`);
 97вҶ’
 98вҶ’    // Send SIGTERM and wait for children to exit (up to 5s)
 99вҶ’    const exitPromises: Promise<void>[] = [];
100вҶ’    for (const child of children) {
101вҶ’      if (child.process.exitCode === null && child.process.signalCode === null) {
102вҶ’        exitPromises.push(
103вҶ’          new Promise<void>((resolve) => {
104вҶ’            child.process.once("exit", resolve);
105вҶ’            child.process.kill("SIGTERM");
106вҶ’          })
107вҶ’        );
108вҶ’      }
109вҶ’    }
110вҶ’
111вҶ’    const drainTimeout = setTimeout(() => {
112вҶ’      // Force kill after 5s if children haven't exited
113вҶ’      for (const child of children) {
114вҶ’        if (child.process.exitCode === null && child.process.signalCode === null) {
115вҶ’          child.process.kill("SIGKILL");
116вҶ’        }
117вҶ’      }
118вҶ’    }, 5000);
119вҶ’
120вҶ’    Promise.all(exitPromises).finally(() => {
121вҶ’      clearTimeout(drainTimeout);
122вҶ’      clearServerInfo();
123вҶ’      blank();
124вҶ’      const bye = gradientText("Thanks for using Deus!", [167, 139, 250], [34, 211, 238]);
125вҶ’      console.log(`  ${bye}`);
126вҶ’      blank();
127вҶ’      process.exit(exitCode);
128вҶ’    });
129вҶ’  }
130вҶ’  process.on("SIGINT", shutdown);
131вҶ’  process.on("SIGTERM", shutdown);
132вҶ’
133вҶ’  // Build extra env vars from config
134вҶ’  const extraEnv: Record<string, string> = {};
135вҶ’  if (config.auth_method === "api_key" && config.anthropic_api_key) {
136вҶ’    extraEnv.ANTHROPIC_API_KEY = config.anthropic_api_key;
137вҶ’  }
138вҶ’
139вҶ’  // в”Җв”Җ Step 1: Agent server в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
140вҶ’  const s1 = createSpinner("Starting agent server...");
141вҶ’  const agentServerUrl = await startProcess({
142вҶ’    name: "agent-server",
143вҶ’    command: nodeCmd,
144вҶ’    args: [paths.agentServer],
145вҶ’    env: { DATABASE_PATH: dbPath, ...extraEnv },
146вҶ’    waitFor: /LISTEN_URL=(.+)/,
147вҶ’    children,
148вҶ’  });
149вҶ’
150вҶ’  if (!agentServerUrl) {
151вҶ’    s1.fail("Agent server failed to start");
152вҶ’    shutdown(1);
153вҶ’    return;
154вҶ’  }
155вҶ’  s1.succeed(`Agent server ${c.dim("ready")}`);
156вҶ’
157вҶ’  // в”Җв”Җ Step 2: Backend в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
158вҶ’  const s2 = createSpinner("Starting backend...");
159вҶ’  const backendPort = await startProcess({
160вҶ’    name: "backend",
161вҶ’    command: nodeCmd,
162вҶ’    args: [paths.backend],
163вҶ’    env: {
164вҶ’      AGENT_SERVER_URL: agentServerUrl,
165вҶ’      DATABASE_PATH: dbPath,
166вҶ’      PORT: "0",
167вҶ’      ...extraEnv,
168вҶ’    },
169вҶ’    waitFor: /\[BACKEND_PORT\](\d+)/,
170вҶ’    children,
171вҶ’  });
172вҶ’
173вҶ’  if (!backendPort) {
174вҶ’    s2.fail("Backend failed to start");
175вҶ’    shutdown(1);
176вҶ’    return;
177вҶ’  }
178вҶ’  s2.succeed(`Backend ${c.dim("ready")}`);
179вҶ’
180вҶ’  const port = parseInt(backendPort, 10);
181вҶ’
182вҶ’  // Write server info for `deus pair` and `deus status`
183вҶ’  writeServerInfo({
184вҶ’    pid: process.pid,
185вҶ’    backendPort: port,
186вҶ’    agentServerUrl,
187вҶ’    startedAt: new Date().toISOString(),
188вҶ’  });
189вҶ’
190вҶ’  // в”Җв”Җ Ready в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
191вҶ’  blank();
192вҶ’  box(
193вҶ’    [
194вҶ’      gradientText("Deus is running", [167, 139, 250], [34, 211, 238]),
195вҶ’      "",
196вҶ’      `API  ${c.dim(`http://localhost:${port}`)}`,
197вҶ’    ],
198вҶ’    { borderColor: c.cyan, width: 38 }
199вҶ’  );
200вҶ’  blank();
201вҶ’
202вҶ’  // в”Җв”Җ Pairing code (if relay enabled) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
203вҶ’  if (config.relay_enabled) {
204вҶ’    // Give the backend a moment to connect to the relay
205вҶ’    await sleep(1500);
206вҶ’
207вҶ’    try {
208вҶ’      await showPairCode(port);
209вҶ’    } catch {
210вҶ’      blank();
211вҶ’      warn("Could not generate pairing code.");
212вҶ’      hint(`Run ${c.cyan("deus pair")} to try again once the relay connects.`);
213вҶ’      blank();
214вҶ’    }
215вҶ’  } else {
216вҶ’    blank();
217вҶ’    hint(`Remote access is disabled. Run ${c.cyan("deus login")} to re-run setup and enable it.`);
218вҶ’    blank();
219вҶ’  }
220вҶ’
221вҶ’  // в”Җв”Җ Status line в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
222вҶ’  blank();
223вҶ’  const startedAt = new Date();
224вҶ’  status = statusLine(() => {
225вҶ’    const elapsed = formatUptime(Date.now() - startedAt.getTime());
226вҶ’    return `${c.dim(`Running for ${elapsed}`)}  ${c.dim(`${sym.bullet} Ctrl+C to stop`)}`;
227вҶ’  }, 2000);
228вҶ’
229вҶ’  // Supervise children вҖ” if either crashes after startup, tear down and exit
230вҶ’  for (const child of children) {
231вҶ’    child.process.on("exit", (code, signal) => {
232вҶ’      if (!shuttingDown) {
233вҶ’        blank();
234вҶ’        warn(
235вҶ’          `${child.name} exited unexpectedly${signal ? ` (${signal})` : code ? ` (code ${code})` : ""}`
236вҶ’        );
237вҶ’        shutdown(1);
238вҶ’      }
239вҶ’    });
240вҶ’  }
241вҶ’
242вҶ’  // Keep the process alive
243вҶ’  await new Promise(() => {});
244вҶ’}
245вҶ’
246вҶ’// в”Җв”Җ Bundle resolution в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
247вҶ’
248вҶ’function resolveBundlePaths(): {
249вҶ’  agentServer: string;
250вҶ’  backend: string;
251вҶ’} | null {
252вҶ’  const cliRoot = resolve(__dirname, "..");
253вҶ’
254вҶ’  // Bundled mode (npm package)
255вҶ’  const bundledDir = join(cliRoot, "bundles");
256вҶ’  if (existsSync(join(bundledDir, "agent-server.bundled.cjs"))) {
257вҶ’    return {
258вҶ’      agentServer: join(bundledDir, "agent-server.bundled.cjs"),
259вҶ’      backend: join(bundledDir, "server.bundled.cjs"),
260вҶ’    };
261вҶ’  }
262вҶ’
263вҶ’  // Dev mode (monorepo)
264вҶ’  const monorepoRoot = resolve(cliRoot, "../..");
265вҶ’  const agentServer = join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs");
266вҶ’  const backend = join(monorepoRoot, "apps/backend/dist/server.bundled.cjs");
267вҶ’
268вҶ’  if (existsSync(agentServer) && existsSync(backend)) {
269вҶ’    return { agentServer, backend };
270вҶ’  }
271вҶ’
272вҶ’  return null;
273вҶ’}
274вҶ’
275вҶ’// в”Җв”Җ Data directory в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
276вҶ’
277вҶ’function resolveDataDir(customDir?: string): string {
278вҶ’  if (customDir) {
279вҶ’    mkdirSync(customDir, { recursive: true });
280вҶ’    return join(customDir, "deus.db");
281вҶ’  }
282вҶ’
283вҶ’  const os = platform();
284вҶ’  let dir: string;
285вҶ’
286вҶ’  if (os === "darwin") {
287вҶ’    dir = join(homedir(), "Library/Application Support/com.deus.app");
288вҶ’  } else if (os === "win32") {
289вҶ’    dir = join(process.env.APPDATA || join(homedir(), "AppData/Roaming"), "com.deus.app");
290вҶ’  } else {
291вҶ’    dir = join(process.env.XDG_DATA_HOME || join(homedir(), ".local/share"), "deus");
292вҶ’  }
293вҶ’
294вҶ’  mkdirSync(dir, { recursive: true });
295вҶ’  return join(dir, "deus.db");
296вҶ’}
297вҶ’
298вҶ’// в”Җв”Җ Node binary resolution в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
299вҶ’
300вҶ’function resolveNodeBinary(): string {
301вҶ’  if (process.env.ELECTRON_RUN_AS_NODE === "1") return process.execPath;
302вҶ’
303вҶ’  try {
304вҶ’    const electronPath = execSync(
305вҶ’      "node -e \"try { console.log(require('electron')) } catch { process.exit(1) }\"",
306вҶ’      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
307вҶ’    ).trim();
308вҶ’
309вҶ’    if (electronPath && existsSync(electronPath)) {
310вҶ’      try {
311вҶ’        execSync(
312вҶ’          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
313вҶ’          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
314вҶ’        );
315вҶ’        return process.execPath;
316вҶ’      } catch {
317вҶ’        return electronPath;
318вҶ’      }
319вҶ’    }
320вҶ’  } catch {
321вҶ’    // ignore вҖ” fall through to default
322вҶ’  }
323вҶ’
324вҶ’  return process.execPath;
325вҶ’}
