327вҶ’// в”Җв”Җ Process spawner в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
328вҶ’
329вҶ’async function startProcess(opts: {
330вҶ’  name: string;
331вҶ’  command: string;
332вҶ’  args: string[];
333вҶ’  env: Record<string, string>;
334вҶ’  waitFor: RegExp;
335вҶ’  children: ProcessInfo[];
336вҶ’  timeoutMs?: number;
337вҶ’}): Promise<string | null> {
338вҶ’  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;
339вҶ’
340вҶ’  return new Promise((resolve) => {
341вҶ’    const processEnv: Record<string, string> = {};
342вҶ’    if (command !== process.execPath && command.includes("Electron")) {
343вҶ’      processEnv.ELECTRON_RUN_AS_NODE = "1";
344вҶ’    }
345вҶ’
346вҶ’    const child = spawn(command, args, {
347вҶ’      stdio: ["ignore", "pipe", "pipe"],
348вҶ’      env: { ...process.env, ...processEnv, ...env },
349вҶ’    });
350вҶ’
351вҶ’    children.push({ process: child, name });
352вҶ’
353вҶ’    let buffer = "";
354вҶ’    let resolved = false;
355вҶ’
356вҶ’    const timeout = setTimeout(() => {
357вҶ’      if (!resolved) {
358вҶ’        resolved = true;
359вҶ’        child.kill("SIGTERM");
360вҶ’        resolve(null);
361вҶ’      }
362вҶ’    }, timeoutMs);
363вҶ’
364вҶ’    function onStdout(data: Buffer) {
365вҶ’      buffer += data.toString();
366вҶ’      const match = buffer.match(waitFor);
367вҶ’      if (match && !resolved) {
368вҶ’        resolved = true;
369вҶ’        clearTimeout(timeout);
370вҶ’        // Stop listening and release the buffer вҖ” process may run for days
371вҶ’        child.stdout?.removeListener("data", onStdout);
372вҶ’        buffer = "";
373вҶ’        resolve(match[1]);
374вҶ’      }
375вҶ’    }
376вҶ’
377вҶ’    child.stdout?.on("data", onStdout);
378вҶ’
379вҶ’    child.on("exit", () => {
380вҶ’      if (!resolved) {
381вҶ’        resolved = true;
382вҶ’        clearTimeout(timeout);
383вҶ’        resolve(null);
384вҶ’      }
385вҶ’    });
386вҶ’  });
387вҶ’}
